import Foundation

/// Detects cmux-owned hook injection in captured agent launch arguments.
public struct AgentCmuxHookInjectionDetector {
    private let containsClaudeHookInjection: ([String]) -> Bool
    private let containsCodexHookInjection: ([String]) -> Bool

    /// Creates a detector that recognizes hook payloads generated by cmux wrappers.
    public init() {
        self.init(
            containsClaudeHookInjection: { args in
                args.indices.contains {
                    AgentLaunchSanitizer.claudeHookSettingsReplacement(args, index: $0) != nil
                }
            },
            containsCodexHookInjection: { args in
                removingCmuxInjectedCodexHookArguments(args).count != args.count
            }
        )
    }

    init(
        containsClaudeHookInjection: @escaping ([String]) -> Bool,
        containsCodexHookInjection: @escaping ([String]) -> Bool
    ) {
        self.containsClaudeHookInjection = containsClaudeHookInjection
        self.containsCodexHookInjection = containsCodexHookInjection
    }

    /// Returns whether `args` contain cmux-owned hook injection for `kind`.
    ///
    /// This identifies only hook payloads generated by cmux wrappers. It does not prove
    /// how the executable was resolved and should not be used as process identity proof.
    public func contains(kind: String, args: [String]) -> Bool {
        switch kind {
        case "claude":
            return containsClaudeHookInjection(args)
        case "codex":
            return containsCodexHookInjection(args)
        default:
            return false
        }
    }
}
